head.script:
scwin.processFlag = "";
scwin.mhno = "";
scwin.gubun = "";
scwin.hid_kcomcd = "DBEX";
scwin.hid_mhno = "";
scwin.hid_seaair = "";
scwin.hid_iogb = "";
scwin.seaair = "";
scwin.iogb = "";
scwin.ccaNo = "";
scwin.userId = "";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.userId = $c.ses.getUserId();
    scwin.seaair = (scwin.params && scwin.params.seaair) ? scwin.params.seaair : "";
    scwin.iogb = (scwin.params && scwin.params.iogb) ? scwin.params.iogb : "";
    scwin.ccaNo = (scwin.params && scwin.params.ccaNo) ? scwin.params.ccaNo : "";

    dma_search.set("kcomcd", scwin.hid_kcomcd);
    dma_bl_search.set("kcomcd", scwin.hid_kcomcd);

    scwin.f_Set("INIT");
    scwin.f_DefaultValue();
    scwin.processFlag = "INIT";

    scwin.f_initSetTab();
    cnd_ed_ccano.setFocus();

    if (scwin.ccaNo != "") {
        scwin.f_Retrieve();
    }
};

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableObjects([lc_seaair, lc_iogb]);
    scwin.f_DisablePopUpObj();
};

scwin.f_initSetTab = function() {
    $c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1]);
    $c.gus.cfViewTab(0);
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            break;
        case 1:
            break;
    }
    $c.gus.cfViewTab(idx);
};

scwin.f_DefaultValue = function() {
    lc_seaair.setValue(scwin.seaair);
    lc_iogb.setValue(scwin.iogb);
    cnd_ed_ccano.setValue(scwin.ccaNo);

    if (lc_seaair.getValue() == "S") {
        chb_chkCwht.setLabel("Measure");
        chb_chkRate.setLabel("Freight Charge");
        chb_chkOther.setLabel("Description");
        chb_chkPcs.setLabel("Package");
        chb_chkDest.setLabel("Vessel/Voyage");

        if (lc_iogb.getValue() == "I") {
            // TODO: io_gb label → "ETA" — body에 io_gb 컴포넌트 없음, 동적 라벨 처리 필요
        } else {
            // TODO: io_gb label → "ETD"
        }
    } else {
        chb_chkCwht.setLabel("Chargeable Weight");
        chb_chkRate.setLabel("Rate");
        chb_chkOther.setLabel("Other Charge");
        chb_chkPcs.setLabel("Pieces");
        chb_chkDest.setLabel("Destination");

        if (lc_iogb.getValue() == "I") {
            // TODO: io_gb label → "Arrival Date"
        } else {
            // TODO: io_gb label → "Onboard Date"
        }
    }
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Create]);
            $c.gus.cfDisableObjects([lc_seaair, lc_iogb]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            if (scwin.processFlag == "RETRIEVE") {
                $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
                $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Print]);
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Update, btn_Save, btn_Delete, btn_Print]);
                $c.gus.cfEnableBtnOnly([btn_Create]);
            }
            break;
        case "CANCEL":
            scwin.f_Set("RETRIEVE");
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

            $c.gus.cfEnableObj(ed_ccano, false);
            $c.gus.cfEnableObj(ed_mblno, false);
            $c.gus.cfEnableObj(lc_mmhno, false);

            $c.gus.cfEnableObj(ed_blno, true);
            $c.gus.cfEnableObj(lc_hmhno, true);
            break;
        case "UPDATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Print]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

            $c.gus.cfEnableObj(ed_ccano, false);
            $c.gus.cfEnableObj(ed_mblno, false);
            $c.gus.cfEnableObj(lc_mmhno, false);

            $c.gus.cfEnableObj(ed_blno, true);
            $c.gus.cfEnableObj(lc_hmhno, true);
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([img_tocd, img_aseq, img_ondt, img_isdt, img_sgcd]);
};

scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([img_tocd, img_aseq, img_ondt, img_isdt, img_sgcd]);
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_ccano.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Correction Notice No"]);
        cnd_ed_ccano.setFocus();
        return;
    }

    scwin.gubun = "Search";

    dma_search.set("ccano", cnd_ed_ccano.getValue().trim());

    await $c.sbm.execute(sbm_retrieve);

    let strClntNo = "";
    if (lc_hmgb.getValue() == "H") {
        strClntNo = ed_blno.getValue().trim();
        if (strClntNo.length > 0) {
            await $c.sbm.execute(sbm_retrieveHmhno);
        } else {
            ds_hmhno.removeAll();
        }
    } else {
        strClntNo = ed_mblno.getValue().trim();
        if (strClntNo.length > 0) {
            await $c.sbm.execute(sbm_retrieveMmhno);
            await scwin.f_MasterInfo();
        } else {
            ds_mmhno.removeAll();
        }
    }
};

scwin.f_Create = function() {
    ds_correctionNotice.removeAll();
    ds_correctionNotice.insertRow(0);
    ds_correctionNoticeFreightList.removeAll();
    ds_inCorrectionNoticeFreightList.removeAll();
    ds_blFreight.removeAll();
    ds_bl.removeAll();
    ds_hmhno.removeAll();
    ds_mmhno.removeAll();

    scwin.f_Set("CREATE");
    ds_correctionNotice.insertRow(0);
    let intRowPosition = ds_correctionNotice.getRowPosition();

    ds_correctionNotice.setCellData(intRowPosition, "kcomcd", "DBEX");

    lc_hmgb.setFocus();
    lc_hmgb.setValue("H");
    $c.gus.cfEnableObj(lc_iogb, true);
};

scwin.f_Update = function() {
    scwin.f_Set("UPDATE");
    ed_tocd.setFocus();
};

scwin.f_Undo = function() {
    ds_correctionNotice.undoAll();
    ds_correctionNoticeFreightList.undoAll();
    ds_inCorrectionNoticeFreightList.undoAll();
    scwin.f_Set("CANCEL");
};

scwin.f_Save = async function() {
    if (ica_isdt.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Issued Date"]);
        ica_isdt.setFocus();
        return;
    }

    if (await scwin.f_ReqFieldChk()) {
        let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
        if (chk) {
            let rowPos = ds_correctionNotice.getRowPosition();
            if (lc_hmgb.getValue() == "H") {
                ds_correctionNotice.setCellData(rowPos, "mhno", lc_hmhno.getValue());
            } else {
                ds_correctionNotice.setCellData(rowPos, "mhno", lc_mmhno.getValue());
            }
            await $c.sbm.execute(sbm_save);
            scwin.processFlag = "RETRIEVE";
            scwin.f_Set("RETRIEVE");
        }
    }
};

scwin.f_Delete = async function() {
    let chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk) {
        let intRowPosition = ds_correctionNotice.getRowPosition();
        ds_correctionNotice.removeRow(intRowPosition);
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([headerMandantory]);
    if (!chk) {
        return false;
    }
    return true;
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_searchCondtion, null);
    cnd_ed_ccano.setFocus();
};

scwin.f_Addrow = function(dsGubun) {
    let intRowPosition;
    switch (dsGubun) {
        case 1:
            ds_correctionNoticeFreightList.insertRow(ds_correctionNoticeFreightList.getRowCount());
            intRowPosition = ds_correctionNoticeFreightList.getRowPosition();
            ds_correctionNoticeFreightList.setCellData(intRowPosition, "kcomcd", scwin.hid_kcomcd);
            break;
        case 2:
            ds_inCorrectionNoticeFreightList.insertRow(ds_inCorrectionNoticeFreightList.getRowCount());
            intRowPosition = ds_inCorrectionNoticeFreightList.getRowPosition();
            ds_inCorrectionNoticeFreightList.setCellData(intRowPosition, "kcomcd", scwin.hid_kcomcd);
            break;
    }
};

scwin.f_Delrow = function(dsGubun) {
    let intRowPosition;
    switch (dsGubun) {
        case 1:
            intRowPosition = ds_correctionNoticeFreightList.getRowPosition();
            if (intRowPosition < 0) return;
            if (ds_correctionNoticeFreightList.getRowStatus(intRowPosition) == "C") {
                ds_correctionNoticeFreightList.undoRow(intRowPosition);
            } else {
                ds_correctionNoticeFreightList.removeRow(intRowPosition);
                if (intRowPosition - 1 >= 0) {
                    ds_correctionNoticeFreightList.setRowPosition(intRowPosition - 1);
                }
            }
            break;
        case 2:
            intRowPosition = ds_inCorrectionNoticeFreightList.getRowPosition();
            if (intRowPosition < 0) return;
            if (ds_inCorrectionNoticeFreightList.getRowStatus(intRowPosition) == "C") {
                ds_inCorrectionNoticeFreightList.undoRow(intRowPosition);
            } else {
                ds_inCorrectionNoticeFreightList.removeRow(intRowPosition);
                if (intRowPosition - 1 >= 0) {
                    ds_inCorrectionNoticeFreightList.setRowPosition(intRowPosition - 1);
                }
            }
            break;
    }
};

scwin.f_PopUp = function(disGubun, chgGubun, img) {
    switch (disGubun) {
        case 1:
            udc_tocd.ilCommonPopUp(scwin.callbackPopUp1,
                ed_tocd.getValue().trim(),
                txt_tonm.getValue(),
                chgGubun,
                '5',
                'To',
                '140,300,300',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                'F',
                'To Search,To Code,To Name');
            break;

        case 2:
            if (img != "img") {
                if (txt_attn.getValue() != "") {
                    break;
                }
            }
            let pParam = ed_tocd.getValue().trim();
            udc_aseq.ilCommonPopUp(scwin.callbackPopUp2,
                ed_aseq.getValue().trim(),
                txt_attn.getValue(),
                chgGubun,
                '4',
                "PIC",
                '100,350',
                null,
                pParam,
                '500',
                '500',
                null,
                null,
                null,
                "T",
                null);
            break;

        case 3:
            udc_sgcd.cfCommonPopUp(scwin.callbackPopUp3,
                ed_sgcd.getValue().trim(),
                txt_sgnm.getValue(),
                chgGubun,
                '4',
                "Signature",
                '100,350',
                null,
                '',
                '500',
                '500',
                null,
                null,
                null,
                "T",
                null);
            break;

        default:
            break;
    }
};

scwin.callbackPopUp1 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_tocd, txt_tonm);
};

scwin.callbackPopUp2 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_aseq, txt_attn);
};

scwin.callbackPopUp3 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_sgcd, txt_sgnm);
};

scwin.f_PopUp2 = function(disGubun, chgGubun, fieldCode, fieldName) {
    switch (disGubun) {
        case 3:
            let seaairVal = lc_seaair.getValue().trim();
            let code = "";
            let name = "";

            if (fieldCode != "" && fieldCode != null) {
                code = fieldCode.getValue().trim();
            }
            if (fieldName != "" && fieldName != null) {
                name = fieldName.getValue();
            }

            if (seaairVal == "S") {
                udc_tocd.cfCommonPopUp(scwin.callbackPopUp2_port,
                    code,
                    name,
                    chgGubun,
                    '5',
                    null,
                    '140,300',
                    null,
                    null,
                    '500',
                    '500',
                    null,
                    null,
                    null,
                    'F',
                    'Departure Port Search,Port Code,Port Name');
            } else {
                udc_tocd.ilCommonPopUp(scwin.callbackPopUp2_port,
                    code,
                    name,
                    chgGubun,
                    '5',
                    'Port Code,Port Name',
                    '140,300',
                    null,
                    null,
                    '500',
                    '500',
                    null,
                    null,
                    null,
                    'F',
                    'Departure Port Search,Port Code,Port Name');
            }

            scwin._popUp2FieldCode = fieldCode;
            break;

        default:
            break;
    }
};

scwin.callbackPopUp2_port = function(rtnList) {
    if (scwin._popUp2FieldCode) {
        $c.gus.cfSetReturnValue(rtnList, scwin._popUp2FieldCode);
    }
};

scwin.f_Chk = function(disGubun) {
    switch (disGubun) {
        case 1:
            if (chb_chkGwht.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "GROSS W/T : " + ds_bl.getCellData(0, "gwgt") + "\r\n");
                    txa_mark2.setValue(txa_mark2.getValue() + "GROSS W/T : " + "\r\n");
                }
            }
            break;

        case 2:
            if (chb_chkCwht.getValue() != "" || chb_chkRate.getValue() != "") {
                if (ds_blFreight.getRowCount() > 0 && ds_correctionNoticeFreightList.getRowCount() < 1) {
                    $c.gus.cfViewTab(1);
                    for (let i = 0; i < ds_blFreight.getRowCount(); i++) {
                        ds_correctionNoticeFreightList.insertRow(ds_correctionNoticeFreightList.getRowCount());
                        let newIdx = ds_correctionNoticeFreightList.getRowCount() - 1;
                        ds_correctionNoticeFreightList.setCellData(newIdx, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "ccano", ds_blFreight.getCellData(i, "ccano"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "icgb", "C");
                        ds_correctionNoticeFreightList.setCellData(newIdx, "fcode", ds_blFreight.getCellData(i, "fcode"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "cwht", ds_blFreight.getCellData(i, "cwht"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "rate", ds_blFreight.getCellData(i, "rate"));
                        ds_correctionNoticeFreightList.setCellData(newIdx, "charge", ds_blFreight.getCellData(i, "charge"));

                        ds_inCorrectionNoticeFreightList.insertRow(ds_inCorrectionNoticeFreightList.getRowCount());
                        let newIdx2 = ds_inCorrectionNoticeFreightList.getRowCount() - 1;
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "ccano", ds_blFreight.getCellData(i, "ccano"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "icgb", ds_blFreight.getCellData(i, "icgb"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "fcode", ds_blFreight.getCellData(i, "fcode"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "cwht", ds_blFreight.getCellData(i, "cwht"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "rate", ds_blFreight.getCellData(i, "rate"));
                        ds_inCorrectionNoticeFreightList.setCellData(newIdx2, "charge", ds_blFreight.getCellData(i, "charge"));
                    }
                }
            }
            break;

        case 3:
            if (chb_chkPcs.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Package : " + ds_bl.getCellData(0, "pkg") + "\r\n");
                    txa_mark2.setValue(txa_mark2.getValue() + "Package : " + "\r\n");
                }
            }
            break;

        case 4:
            if (chb_chkCn.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Consignee : " + "\r\n   " + ds_bl.getCellData(0, "cnnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "cnnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "cnnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Consignee : " + "\r\n   ");
                }
            }
            break;

        case 5:
            if (chb_chkSh.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Shipper : " + "\r\n   " + ds_bl.getCellData(0, "shnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "shnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "shnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Shipper : " + "\r\n   ");
                }
            }
            break;

        case 6:
            if (chb_chkDest.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Vessel/Voyage : " + ds_bl.getCellData(0, "vsl") + "/" + ds_bl.getCellData(0, "vyg") + "\r\n");
                    txa_mark2.setValue(txa_mark2.getValue() + "Vessel/Voyage : " + "\r\n");
                }
            }
            break;

        case 7:
            if (chb_chkNt.getValue() != "") {
                $c.gus.cfViewTab(0);
                if (ds_bl.getRowCount() > 0) {
                    txa_mark1.setValue(txa_mark1.getValue() + "Notify  : " + "\r\n   " + ds_bl.getCellData(0, "ntnm1") + "\r\n");
                    if (ds_bl.getCellData(0, "ntnm2") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm2") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm3") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm3") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm4") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm4") + "\r\n");
                    }
                    if (ds_bl.getCellData(0, "ntnm5") != "") {
                        txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm5") + "\r\n");
                    }
                    txa_mark2.setValue(txa_mark2.getValue() + "Notify  : " + "\r\n   ");
                }
            }
            break;

        default:
            break;
    }
};

scwin.f_Print = function() {
    let odiParam = new ODIParam("se_112_01_01");
    odiParam.add("KCOMCD", scwin.hid_kcomcd);
    odiParam.add("CCANO", ed_ccano.getValue().trim());
    odiParam.add("USERID", scwin.userId);

    let formParam = new FormParam();

    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.useprogressbar", "false");

    $c.gus.cfOZPreview("/il/seaout/se_112_01_01.ozr", odiParam, viewerParam, formParam);
};

scwin.f_openPgm = function(name) {
    if (name == "Find") {
        let strPath = "/ui/il/airout/aoth/ar_108_01_02b.xml";
        let paramObj = {
            seaair: lc_seaair.getValue(),
            iogb: lc_iogb.getValue()
        };
        $c.win.openMenu("Correction Notice Search", strPath, "ar_108_01_02b.xml", paramObj);
    }
};

scwin.f_HouseInfo = async function() {
    let strClntNo = ed_blno.getValue().trim();
    if (strClntNo.length > 0) {
        await $c.sbm.execute(sbm_retrieveHouseInfo);
