scwin.sbm_retrieveBl_submitdone = async function(e) {
    if (ds_bl.getRowCount() == 0) {
        await $c.win.alert("BL 정보가 없습니다.");
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        ds_correctionNotice.removeAll();
        ds_correctionNotice.insertRow(0);
        let i = ds_correctionNotice.getRowPosition();
        let k = ds_bl.getRowPosition();
        ds_correctionNotice.setCellData(i, "kcomcd", ds_bl.getCellData(k, "kcomcd"));

        if (ds_bl.getCellData(k, "hmgb") == "H") {
            ds_correctionNotice.setCellData(i, "blno", ds_bl.getCellData(k, "blno"));
            ds_correctionNotice.setCellData(i, "mhno", lc_hmhno.getValue());
        } else {
            ds_correctionNotice.setCellData(i, "mblno", ds_bl.getCellData(k, "blno"));
            ds_correctionNotice.setCellData(i, "mhno", lc_mmhno.getValue());
        }
        ds_correctionNotice.setCellData(i, "iogb", lc_iogb.getValue());
        ds_correctionNotice.setCellData(i, "seaair", lc_seaair.getValue());
        ds_correctionNotice.setCellData(i, "hmgb", ds_bl.getCellData(k, "hmgb"));
        ds_correctionNotice.setCellData(i, "curr", ds_bl.getCellData(k, "cucd"));
        ica_ondt.setValue(ds_bl.getCellData(k, "stdt"));
        ds_correctionNotice.setCellData(i, "ondt", ds_bl.getCellData(k, "stdt"));
        ds_correctionNotice.setCellData(i, "idest", ds_bl.getCellData(k, "dpcd"));
        ds_correctionNotice.setCellData(i, "idscd1", ds_bl.getCellData(k, "dscd1"));
        ds_correctionNotice.setCellData(i, "iptcd1", ds_bl.getCellData(k, "ptcd1"));
        ds_correctionNotice.setCellData(i, "idscd2", ds_bl.getCellData(k, "dscd2"));
        ds_correctionNotice.setCellData(i, "iptcd2", ds_bl.getCellData(k, "ptcd2"));
        ds_correctionNotice.setCellData(i, "idscd3", ds_bl.getCellData(k, "dscd3"));
        ds_correctionNotice.setCellData(i, "iptcd3", ds_bl.getCellData(k, "ptcd3"));
        ds_correctionNotice.setCellData(i, "vsl", ds_bl.getCellData(k, "vsl"));
        ds_correctionNotice.setCellData(i, "vyg", ds_bl.getCellData(k, "vyg"));
    }
};

