scwin.ds_correctionNotice_onloadcompleted = async function(e) {
    let rowcnt = ds_correctionNotice.getRowCount();
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    }
};

scwin.ds_correctionNotice_onrowpositionchange = function(e) {
    let row = ds_correctionNotice.getRowPosition();
    let vRowStatus = ds_correctionNotice.getRowStatus(row);

    if (row >= 0) {
        if (vRowStatus == "R") {
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Print, btn_Create, btn_Update, btn_Delete]);
            scwin.processFlag = "RETRIEVE";
        } else if (vRowStatus == "C") {
            scwin.f_Set("CREATE");
        } else if (vRowStatus == "U") {
            scwin.f_Set("UPDATE");
        }
    } else {
        scwin.f_Set("INIT");
        scwin.processFlag = "INIT";
    }
};

