scwin.lc_hmgb_onchange = function(e) {
    if (lc_hmgb.getValue() == "H") {
        $c.gus.cfEnableObj(ed_blno, true);
        $c.gus.cfEnableObj(lc_hmhno, true);
        $c.gus.cfEnableObj(ed_mblno, false);
        $c.gus.cfEnableObj(lc_mmhno, false);

        ed_mblno.setValue("");
        ds_mmhno.removeAll();
    } else {
        $c.gus.cfEnableObj(ed_blno, false);
        $c.gus.cfEnableObj(lc_hmhno, false);
        $c.gus.cfEnableObj(ed_mblno, true);
        $c.gus.cfEnableObj(lc_mmhno, true);

        ed_blno.setValue("");
        ds_hmhno.removeAll();
    }
};

